1	const PROCESSING_FEE = 5;
2	const FIRST_INSURANCE_RATE = 0.1;
3	
4	const BASE_PREMIUM: Record<string, number> = {
5	  sword: 100,
6	  amulet: 60,
7	  staff: 80,
8	  potion: 40,
9	  rune: 25,
10	  moonstone: 25,
11	};
12	
13	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
14	const COMPONENT_BLOCK_SIZE = 3;
15	const COMPONENT_BLOCK_PRICE = 60;
16	
17	interface Item {
18	  type: string;
19	  cursed?: boolean;
20	}
21	
22	interface QuoteStep {
23	  op: "quote";
24	  items: Item[];
25	}
26	
27	interface Scenario {
28	  customer: { yearsWithMHPCO: number };
29	  steps: QuoteStep[];
30	}
31	
32	export function runScenario(input: unknown): unknown {
33	  const scenario = input as Scenario;
34	  const results = scenario.steps.map((step) => {
35	    const countsByType: Record<string, number> = {};
36	    for (const item of step.items) {
37	      countsByType[item.type] = (countsByType[item.type] ?? 0) + 1;
38	    }
39	    let basePremium = 0;
40	    for (const [type, count] of Object.entries(countsByType)) {
41	      if (COMPONENT_TYPES.has(type) && count === COMPONENT_BLOCK_SIZE) {
42	        basePremium += COMPONENT_BLOCK_PRICE;
43	      } else {
44	        const perItem = BASE_PREMIUM[type] ?? 0;
45	        basePremium += perItem * count;
46	      }
47	    }
48	    let cursedSurcharge = 0;
49	    for (const item of step.items) {
50	      if (item.cursed) {
51	        cursedSurcharge += (BASE_PREMIUM[item.type] ?? 0) * 0.5;
52	      }
53	    }
54	    const firstInsurance = basePremium * FIRST_INSURANCE_RATE;
55	    const rawPremium = basePremium + cursedSurcharge + firstInsurance + PROCESSING_FEE;
56	    const premium = Math.ceil(rawPremium);
57	    return { premium };
58	  });
59	  return { results };
60	}
